/* CompTIA AI Essentials :: content/quiz1.js — question bank for Domain 1 "AI & GenAI Foundations" (100 items). */
window.AIESS = window.AIESS || {}; AIESS.questions = AIESS.questions || [];
AIESS.questions.push(
{ id:"D1-001", domain:1, obj:"1.1", diff:"easy", q:"Which statement BEST describes the relationship between artificial intelligence (AI) and machine learning (ML)?", options:["Machine learning is a subset of artificial intelligence that learns patterns from data","Machine learning is a broad field that contains artificial intelligence","Artificial intelligence and machine learning are completely unrelated fields","Artificial intelligence only exists inside machine learning models"], answer:0, explain:"<strong>Machine learning is a subset of artificial intelligence that learns patterns from data</strong> is correct because AI is the broad goal of making machines act intelligently, and ML is one approach within it where systems improve by learning from examples rather than following hand-written rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Machine learning is a broad field that contains artificial intelligence</b>: this reverses the relationship, since AI is the wider umbrella and ML sits inside it.</span><span class='qd'><b>Artificial intelligence and machine learning are completely unrelated fields</b>: they are closely related, with ML being a major branch of AI.</span><span class='qd'><b>Artificial intelligence only exists inside machine learning models</b>: AI also includes rule-based and other approaches that are not machine learning.</span>" },
{ id:"D1-002", domain:1, obj:"1.1", diff:"easy", q:"What does the abbreviation LLM stand for in the context of modern AI tools?", options:["Logical Learning Machine","Large Language Model","Linked Local Memory","Long List Method"], answer:1, explain:"<strong>Large Language Model</strong> is correct because tools like ChatGPT and Claude are built on large language models, which are AI systems trained on huge amounts of text to work with human language.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Logical Learning Machine</b>: this is not a real term for the technology behind chat assistants.</span><span class='qd'><b>Linked Local Memory</b>: this invented phrase has nothing to do with language models.</span><span class='qd'><b>Long List Method</b>: this is not what LLM refers to and is not an AI concept.</span>" },
{ id:"D1-003", domain:1, obj:"1.1", diff:"easy", q:"Generative AI is a category of AI that is designed primarily to:", options:["Block unwanted email based on fixed rules","Store files securely in the cloud","Create new content such as text, images, or code","Speed up your computer's processor"], answer:2, explain:"<strong>Create new content such as text, images, or code</strong> is correct because generative AI produces original output like written passages, pictures, or software rather than simply retrieving or filtering existing data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Block unwanted email based on fixed rules</b>: filtering spam is a classification task, not the generation of new content.</span><span class='qd'><b>Store files securely in the cloud</b>: storing files is a storage function unrelated to generating content.</span><span class='qd'><b>Speed up your computer's processor</b>: generative AI does not make hardware faster and can actually be resource-intensive.</span>" },
{ id:"D1-004", domain:1, obj:"1.1", diff:"easy", q:"Which of the following is the BEST example of generative AI in everyday use?", options:["A calculator adding two numbers","A thermostat turning on the heat at a set temperature","A barcode scanner reading a price tag","A chat assistant writing a first draft of an email for you"], answer:3, explain:"<strong>A chat assistant writing a first draft of an email for you</strong> is correct because producing original written text on request is exactly what generative AI does.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A calculator adding two numbers</b>: a calculator performs fixed arithmetic and creates no new content.</span><span class='qd'><b>A thermostat turning on the heat at a set temperature</b>: a thermostat follows a simple threshold rule, not content generation.</span><span class='qd'><b>A barcode scanner reading a price tag</b>: a scanner reads existing data rather than generating anything new.</span>" },
{ id:"D1-005", domain:1, obj:"1.1", diff:"medium", q:"A colleague says, \"All AI is generative AI.\" Why is that statement incorrect?", options:["AI includes many non-generative tasks such as detecting spam or recommending products","Generative AI is only used in video games","Generative AI was never actually released to the public","All AI must generate images to qualify as AI"], answer:0, explain:"<strong>AI includes many non-generative tasks such as detecting spam or recommending products</strong> is correct because generative AI is just one branch, while other AI systems classify, predict, or recommend without creating new content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generative AI is only used in video games</b>: generative AI is used across writing, images, code, and many fields, and this does not explain the error.</span><span class='qd'><b>Generative AI was never actually released to the public</b>: generative AI tools are widely available, so this is false.</span><span class='qd'><b>All AI must generate images to qualify as AI</b>: AI does not need to generate images at all, and many AI systems handle other tasks.</span>" },
{ id:"D1-006", domain:1, obj:"1.1", diff:"medium", q:"Which description BEST captures how a large language model relates to generative AI?", options:["A large language model is unrelated to generative AI","A large language model is a type of generative AI focused on producing text","Generative AI is a feature inside every large language model's hardware","A large language model can only summarize, never generate"], answer:1, explain:"<strong>A large language model is a type of generative AI focused on producing text</strong> is correct because LLMs are generative systems specialized for language, generating written output from patterns learned in training text.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A large language model is unrelated to generative AI</b>: LLMs are a core example of generative AI, so they are directly related.</span><span class='qd'><b>Generative AI is a feature inside every large language model's hardware</b>: generative AI is a category of capability, not a hardware feature, and this confuses the terms.</span><span class='qd'><b>A large language model can only summarize, never generate</b>: LLMs generate a wide range of text, including drafts and answers, not just summaries.</span>" },
{ id:"D1-007", domain:1, obj:"1.1", diff:"medium", q:"You hear the terms AI, machine learning, and generative AI used together. Which ordering correctly goes from broadest to most specific?", options:["Generative AI, then machine learning, then artificial intelligence","Machine learning, then artificial intelligence, then generative AI","Artificial intelligence, then machine learning, then generative AI","Artificial intelligence, then generative AI, then machine learning"], answer:2, explain:"<strong>Artificial intelligence, then machine learning, then generative AI</strong> is correct because AI is the broadest field, machine learning is a subset of AI, and generative AI is a subset that produces content, often built with machine learning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generative AI, then machine learning, then artificial intelligence</b>: this lists them from most specific to broadest, the reverse of what was asked.</span><span class='qd'><b>Machine learning, then artificial intelligence, then generative AI</b>: this incorrectly places AI inside machine learning.</span><span class='qd'><b>Artificial intelligence, then generative AI, then machine learning</b>: this misorders the middle terms, since machine learning is broader than generative AI.</span>" },
{ id:"D1-008", domain:1, obj:"1.1", diff:"medium", q:"Which real-world scenario is an example of AI that is NOT generative AI?", options:["A tool that writes a poem about autumn","An assistant that drafts a cover letter","An app that turns a text prompt into an image","A bank system that flags a transaction as likely fraud"], answer:3, explain:"<strong>A bank system that flags a transaction as likely fraud</strong> is correct because fraud detection classifies activity as suspicious or not, which is a predictive task rather than the creation of new content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A tool that writes a poem about autumn</b>: writing a poem is generating new text, which is generative AI.</span><span class='qd'><b>An assistant that drafts a cover letter</b>: drafting a letter creates new content, so it is generative.</span><span class='qd'><b>An app that turns a text prompt into an image</b>: producing an image from a prompt is generative AI.</span>" },
{ id:"D1-009", domain:1, obj:"1.1", diff:"hard", q:"A manager insists that because a chatbot answers questions fluently, it must truly understand the topic the way a human expert does. What is the BEST correction?", options:["The chatbot generates fluent-sounding text from learned patterns without genuine understanding","The chatbot understands better than any human because it read more books","Fluent output always guarantees the answer is factually correct","Chatbots only repeat sentences word-for-word from a fixed database"], answer:0, explain:"<strong>The chatbot generates fluent-sounding text from learned patterns without genuine understanding</strong> is correct because a language model predicts likely wording based on training patterns; fluency does not mean it comprehends meaning or verifies facts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The chatbot understands better than any human because it read more books</b>: processing lots of text is not the same as human understanding, and this overstates the tool's abilities.</span><span class='qd'><b>Fluent output always guarantees the answer is factually correct</b>: fluent text can still be wrong, so fluency is not proof of accuracy.</span><span class='qd'><b>Chatbots only repeat sentences word-for-word from a fixed database</b>: modern models generate new wording rather than copying stored sentences verbatim.</span>" },
{ id:"D1-010", domain:1, obj:"1.1", diff:"hard", q:"Which statement most accurately distinguishes traditional rule-based AI from machine-learning-based AI?", options:["Rule-based AI learns on its own from examples, while machine learning uses fixed human rules","Rule-based AI follows explicit human-written rules, while machine learning discovers patterns from data","There is no difference between the two approaches","Machine learning cannot be considered a form of AI"], answer:1, explain:"<strong>Rule-based AI follows explicit human-written rules, while machine learning discovers patterns from data</strong> is correct because rule-based systems act on logic that people program directly, whereas machine learning derives its behavior from patterns found in training data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rule-based AI learns on its own from examples, while machine learning uses fixed human rules</b>: this swaps the two descriptions, reversing how each approach works.</span><span class='qd'><b>There is no difference between the two approaches</b>: they differ fundamentally in whether behavior is programmed or learned.</span><span class='qd'><b>Machine learning cannot be considered a form of AI</b>: machine learning is a well-established branch of AI.</span>" },
{ id:"D1-011", domain:1, obj:"1.1", diff:"hard", q:"An executive claims that generative AI is a brand-new invention with no connection to earlier AI research. Which response is MOST accurate?", options:["Generative AI appeared overnight with no prior foundation","Generative AI replaced all older forms of AI completely","Generative AI builds on decades of AI and machine learning research and is not entirely new","Generative AI is only a marketing label with no real technology"], answer:2, explain:"<strong>Generative AI builds on decades of AI and machine learning research and is not entirely new</strong> is correct because today's generative tools rest on long-running advances in AI, machine learning, and neural networks rather than emerging from nothing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generative AI appeared overnight with no prior foundation</b>: it is the product of years of accumulated research, so it did not appear from nowhere.</span><span class='qd'><b>Generative AI replaced all older forms of AI completely</b>: many non-generative AI systems remain in wide use alongside generative tools.</span><span class='qd'><b>Generative AI is only a marketing label with no real technology</b>: generative AI reflects genuine, working technology, not just a label.</span>" },
{ id:"D1-012", domain:1, obj:"1.1", diff:"easy", q:"Which of the following is a common everyday task that generative AI can help with?", options:["Physically printing a document on paper","Charging your phone battery","Cleaning dust from a keyboard","Brainstorming ideas for a birthday party theme"], answer:3, explain:"<strong>Brainstorming ideas for a birthday party theme</strong> is correct because generating ideas and suggestions from a prompt is a natural, everyday use of generative AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physically printing a document on paper</b>: printing is a hardware action that AI does not perform.</span><span class='qd'><b>Charging your phone battery</b>: charging is an electrical task unrelated to AI.</span><span class='qd'><b>Cleaning dust from a keyboard</b>: cleaning hardware is a physical chore with no AI involvement.</span>" },
{ id:"D1-013", domain:1, obj:"1.1", diff:"easy", q:"A person says they want to \"summarize a long article quickly.\" Which type of tool is well suited to this?", options:["A generative AI assistant that can condense text","A screen magnifier","A file backup service","A battery saver app"], answer:0, explain:"<strong>A generative AI assistant that can condense text</strong> is correct because summarizing long text into a short version is a core strength of generative AI language tools.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A screen magnifier</b>: a magnifier only enlarges what is on screen and does not shorten content.</span><span class='qd'><b>A file backup service</b>: backup copies files and does not summarize them.</span><span class='qd'><b>A battery saver app</b>: a battery saver manages power and has nothing to do with summarizing text.</span>" },
{ id:"D1-014", domain:1, obj:"1.1", diff:"medium", q:"Which statement BEST explains why generative AI is called \"generative\"?", options:["It generates electricity for data centers","It generates new content rather than only retrieving stored answers","It generates network traffic to slow down competitors","It generates hardware components automatically"], answer:1, explain:"<strong>It generates new content rather than only retrieving stored answers</strong> is correct because the defining feature of generative AI is producing original output such as text or images instead of merely looking up existing data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It generates electricity for data centers</b>: generative AI does not produce electricity, and the name refers to content.</span><span class='qd'><b>It generates network traffic to slow down competitors</b>: this is unrelated to what generative means and is not a real function.</span><span class='qd'><b>It generates hardware components automatically</b>: it creates digital content, not physical hardware.</span>" },
{ id:"D1-015", domain:1, obj:"1.1", diff:"medium", q:"Why might it be useful to know that an LLM is a form of machine learning?", options:["Because it means the model was hand-coded with every possible answer","Because it proves the model can never make mistakes","Because it explains that the model learned language patterns from data rather than fixed rules","Because it means the model has no need for any training data"], answer:2, explain:"<strong>Because it explains that the model learned language patterns from data rather than fixed rules</strong> is correct because recognizing an LLM as machine learning clarifies that its abilities come from patterns in training data, which also explains why it can be inconsistent or wrong.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because it means the model was hand-coded with every possible answer</b>: machine learning models are not hand-coded with fixed answers; they learn from data.</span><span class='qd'><b>Because it proves the model can never make mistakes</b>: learning from data does not make a model error-free.</span><span class='qd'><b>Because it means the model has no need for any training data</b>: machine learning specifically depends on training data.</span>" },
{ id:"D1-016", domain:1, obj:"1.1", diff:"hard", q:"A student argues that ChatGPT and a spam filter cannot both be AI because they seem so different. What is the BEST explanation?", options:["Only ChatGPT counts as AI because it talks","A spam filter is AI but ChatGPT is not","Neither one is actually AI","AI is a broad field, so both a text generator and a classifier can be different kinds of AI"], answer:3, explain:"<strong>AI is a broad field, so both a text generator and a classifier can be different kinds of AI</strong> is correct because AI covers many task types; generating text and classifying spam are simply different applications under the same umbrella.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only ChatGPT counts as AI because it talks</b>: the ability to converse is not the requirement for something to be AI.</span><span class='qd'><b>A spam filter is AI but ChatGPT is not</b>: both are AI, so excluding ChatGPT is incorrect.</span><span class='qd'><b>Neither one is actually AI</b>: both are recognized applications of AI.</span>" },
{ id:"D1-017", domain:1, obj:"1.1", diff:"medium", q:"Which of the following BEST describes the everyday value of generative AI for a typical office worker?", options:["It can speed up drafting, summarizing, and brainstorming that the worker then refines","It replaces the need to ever review any work","It guarantees perfect accuracy on every task","It only benefits software engineers"], answer:0, explain:"<strong>It can speed up drafting, summarizing, and brainstorming that the worker then refines</strong> is correct because generative AI is most valuable as a productivity aid for first drafts and ideas that a person reviews and improves.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It replaces the need to ever review any work</b>: human review remains essential because AI output can contain errors.</span><span class='qd'><b>It guarantees perfect accuracy on every task</b>: generative AI does not guarantee accuracy and can be wrong.</span><span class='qd'><b>It only benefits software engineers</b>: it helps a wide range of roles, not just engineers.</span>" },
{ id:"D1-018", domain:1, obj:"1.1", diff:"easy", q:"Which pairing correctly matches a term to its meaning?", options:["AI means only robots with arms and legs","Generative AI means AI that creates new content like text or images","Machine learning means memorizing a printed manual","LLM means a small program with no training"], answer:1, explain:"<strong>Generative AI means AI that creates new content like text or images</strong> is correct because that is the accurate definition of generative AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI means only robots with arms and legs</b>: AI is software intelligence and does not require a physical robot body.</span><span class='qd'><b>Machine learning means memorizing a printed manual</b>: machine learning learns patterns from data, not by memorizing a manual.</span><span class='qd'><b>LLM means a small program with no training</b>: an LLM is a large model trained on vast text, not a small untrained program.</span>" },
{ id:"D1-019", domain:1, obj:"1.1", diff:"medium", q:"A team wants to explain to non-technical staff what a large language model does in plain terms. Which explanation is BEST?", options:["It is a physical server that stores every book ever written","It is a search engine that only returns web links","It is a program that predicts and produces likely text based on patterns it learned from lots of writing","It is a spreadsheet that calculates numbers"], answer:2, explain:"<strong>It is a program that predicts and produces likely text based on patterns it learned from lots of writing</strong> is correct because this plainly and accurately describes how an LLM works for a general audience.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is a physical server that stores every book ever written</b>: an LLM does not store every book verbatim; it learns patterns from text.</span><span class='qd'><b>It is a search engine that only returns web links</b>: an LLM generates text rather than returning a list of links.</span><span class='qd'><b>It is a spreadsheet that calculates numbers</b>: an LLM works with language, not spreadsheet calculations.</span>" },
{ id:"D1-020", domain:1, obj:"1.1", diff:"hard", q:"Which comparison correctly separates machine learning from generative AI?", options:["All machine learning is generative, and all generative AI is machine learning","Machine learning always produces images","Generative AI never involves any learning from data","Generative AI often uses machine learning, but not all machine learning produces new content"], answer:3, explain:"<strong>Generative AI often uses machine learning, but not all machine learning produces new content</strong> is correct because many machine learning systems classify or predict without generating content, while generative AI is the subset focused on creating output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>All machine learning is generative, and all generative AI is machine learning</b>: much machine learning is not generative, so the first half is false.</span><span class='qd'><b>Machine learning always produces images</b>: machine learning handles many tasks and does not always produce images.</span><span class='qd'><b>Generative AI never involves any learning from data</b>: generative AI typically depends on learning from large training data.</span>" },
{ id:"D1-021", domain:1, obj:"1.2", diff:"easy", q:"At a high level, how does a generative AI language model decide what to write next?", options:["It predicts the most likely next word or token based on patterns in its training data","It looks up the exact answer in a verified encyclopedia","It asks a human editor to type each word","It randomly selects letters with no pattern"], answer:0, explain:"<strong>It predicts the most likely next word or token based on patterns in its training data</strong> is correct because a language model works by repeatedly predicting probable next tokens learned from the text it was trained on.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It looks up the exact answer in a verified encyclopedia</b>: the model does not look up verified facts; it predicts likely wording.</span><span class='qd'><b>It asks a human editor to type each word</b>: no human types the words; the model generates them automatically.</span><span class='qd'><b>It randomly selects letters with no pattern</b>: output follows learned probabilities, not random letters.</span>" },
{ id:"D1-022", domain:1, obj:"1.2", diff:"easy", q:"A generative AI model produces a confident-sounding answer that turns out to be false. This kind of made-up but plausible output is commonly called a:", options:["Backup","Hallucination","Firewall","Spreadsheet"], answer:1, explain:"<strong>Hallucination</strong> is correct because a hallucination is when a generative AI produces content that sounds convincing but is inaccurate or fabricated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Backup</b>: a backup is a saved copy of data and has nothing to do with false AI output.</span><span class='qd'><b>Firewall</b>: a firewall filters network traffic and is unrelated to model accuracy.</span><span class='qd'><b>Spreadsheet</b>: a spreadsheet is a data tool, not a term for incorrect AI output.</span>" },
{ id:"D1-023", domain:1, obj:"1.2", diff:"easy", q:"Which statement about how generative AI \"knows\" facts is MOST accurate?", options:["It stores a perfect, always-current database of facts","It verifies every answer against a live fact-checker automatically","It does not truly know facts; it produces likely text from patterns and can be wrong","It only outputs information a human just typed into it"], answer:2, explain:"<strong>It does not truly know facts; it produces likely text from patterns and can be wrong</strong> is correct because a generative model predicts plausible wording rather than retrieving verified knowledge, so its statements can be inaccurate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It stores a perfect, always-current database of facts</b>: it does not hold a perfect or current fact database.</span><span class='qd'><b>It verifies every answer against a live fact-checker automatically</b>: standard generative models do not automatically fact-check every answer.</span><span class='qd'><b>It only outputs information a human just typed into it</b>: it generates new text beyond whatever the user typed.</span>" },
{ id:"D1-024", domain:1, obj:"1.2", diff:"medium", q:"Why can two people ask a generative AI the exact same question and sometimes get differently worded answers?", options:["The model deletes its memory after each user","The model is broken and should be uninstalled","The model copies answers from the other user's screen","The model generates responses probabilistically, so wording can vary"], answer:3, explain:"<strong>The model generates responses probabilistically, so wording can vary</strong> is correct because the model chooses among likely next tokens, which can lead to different phrasings for the same prompt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model deletes its memory after each user</b>: memory handling is not why identical prompts can produce varied wording.</span><span class='qd'><b>The model is broken and should be uninstalled</b>: varied wording is normal behavior, not a defect.</span><span class='qd'><b>The model copies answers from the other user's screen</b>: models do not read other users' screens.</span>" },
{ id:"D1-025", domain:1, obj:"1.2", diff:"medium", q:"A user asks a generative AI for the current stock price of a company. Why should the user be cautious about the answer?", options:["The model may not have live data and could produce an outdated or made-up figure","The model always has real-time market data","The model is legally required to be correct","The model refuses to answer any finance question"], answer:0, explain:"<strong>The model may not have live data and could produce an outdated or made-up figure</strong> is correct because generative models are trained on past data and generally do not have real-time information, so a number they give may be stale or invented.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model always has real-time market data</b>: base models typically lack live market feeds.</span><span class='qd'><b>The model is legally required to be correct</b>: there is no such legal guarantee of correctness.</span><span class='qd'><b>The model refuses to answer any finance question</b>: models will answer finance questions, which is exactly why caution is needed.</span>" },
{ id:"D1-026", domain:1, obj:"1.2", diff:"medium", q:"Which phrase BEST describes what generative AI is doing when it writes a sentence?", options:["Retrieving a stored, verified paragraph","Predicting likely next tokens one after another to form text","Solving a math proof step by step","Scanning the internet in real time for the exact wording"], answer:1, explain:"<strong>Predicting likely next tokens one after another to form text</strong> is correct because language models build output token by token based on probability, not by retrieving stored paragraphs or browsing live.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Retrieving a stored, verified paragraph</b>: the model generates new text rather than pulling a stored verified paragraph.</span><span class='qd'><b>Solving a math proof step by step</b>: it predicts likely wording and is not inherently performing rigorous math.</span><span class='qd'><b>Scanning the internet in real time for the exact wording</b>: a standard model is not browsing the live internet as it writes.</span>" },
{ id:"D1-027", domain:1, obj:"1.2", diff:"hard", q:"An analyst notices a generative AI confidently cited a study that does not exist. Which explanation is MOST accurate?", options:["The tool intentionally lied to deceive the user","The study must exist because the model mentioned it","The model produced a plausible-looking citation as a hallucination, not a verified reference","The model was hacked to insert fake citations"], answer:2, explain:"<strong>The model produced a plausible-looking citation as a hallucination, not a verified reference</strong> is correct because models can generate realistic but fabricated references since they predict likely text rather than confirming sources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The tool intentionally lied to deceive the user</b>: the model has no intent; it generated plausible text without verifying it.</span><span class='qd'><b>The study must exist because the model mentioned it</b>: a mention is not proof of existence, so this is unsafe to assume.</span><span class='qd'><b>The model was hacked to insert fake citations</b>: fabricated citations are a normal risk of generation, not evidence of a hack.</span>" },
{ id:"D1-028", domain:1, obj:"1.2", diff:"hard", q:"Why is it accurate to say a generative AI model \"has no built-in sense of truth\"?", options:["Because it deliberately avoids the truth","Because it only outputs random noise","Because it always cites official sources","Because it optimizes for producing likely-sounding text, not for verifying factual accuracy"], answer:3, explain:"<strong>Because it optimizes for producing likely-sounding text, not for verifying factual accuracy</strong> is correct because a model aims to generate plausible language patterns and does not independently check whether statements are true.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because it deliberately avoids the truth</b>: it has no intent to avoid truth; it simply does not verify it.</span><span class='qd'><b>Because it only outputs random noise</b>: output is structured and coherent, not random noise.</span><span class='qd'><b>Because it always cites official sources</b>: it does not reliably cite official sources and can fabricate them.</span>" },
{ id:"D1-029", domain:1, obj:"1.2", diff:"medium", q:"A generative AI is trained on data up to a certain date. What is the practical implication for users?", options:["The model may be unaware of very recent events after its training cutoff","The model knows nothing at all","The model updates itself instantly every second","The model can predict future events reliably"], answer:0, explain:"<strong>The model may be unaware of very recent events after its training cutoff</strong> is correct because a model reflects what was in its training data, so it can lack knowledge of events that happened afterward.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model knows nothing at all</b>: it does contain knowledge up to its training cutoff.</span><span class='qd'><b>The model updates itself instantly every second</b>: a base model does not continuously update in real time.</span><span class='qd'><b>The model can predict future events reliably</b>: it cannot reliably foresee future events.</span>" },
{ id:"D1-030", domain:1, obj:"1.2", diff:"easy", q:"Which habit BEST helps a user deal with the uncertainty in generative AI output?", options:["Trusting every answer without checking","Verifying important facts from reliable sources before relying on them","Assuming the AI is always wrong and ignoring it","Never asking the AI any questions"], answer:1, explain:"<strong>Verifying important facts from reliable sources before relying on them</strong> is correct because checking key claims protects against the model's tendency to produce confident but possibly incorrect output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trusting every answer without checking</b>: blind trust ignores the real risk of errors.</span><span class='qd'><b>Assuming the AI is always wrong and ignoring it</b>: dismissing it entirely wastes a useful tool that is often helpful.</span><span class='qd'><b>Never asking the AI any questions</b>: avoiding the tool altogether is unnecessary when verification manages the risk.</span>" },
{ id:"D1-031", domain:1, obj:"1.2", diff:"medium", q:"A generative AI gives a very confident answer to a niche question. How should the user interpret that confidence?", options:["Confidence proves the answer is correct","The model must have consulted an expert","Confident tone does not guarantee accuracy and should be verified","Confidence means the model checked a database"], answer:2, explain:"<strong>Confident tone does not guarantee accuracy and should be verified</strong> is correct because a model can express certainty even when wrong, so tone is not a reliable signal of truth.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confidence proves the answer is correct</b>: confident wording can accompany false statements.</span><span class='qd'><b>The model must have consulted an expert</b>: the model does not consult a live expert to answer.</span><span class='qd'><b>Confidence means the model checked a database</b>: confidence does not imply any fact-checking occurred.</span>" },
{ id:"D1-032", domain:1, obj:"1.2", diff:"hard", q:"Which explanation BEST describes why generative AI can be excellent at drafting but unreliable for exact facts?", options:["It is designed only for math and cannot write","It always fabricates every word it produces","It is limited to copying text verbatim from one source","It is designed to produce fluent language patterns, which suits drafting more than precise fact recall"], answer:3, explain:"<strong>It is designed to produce fluent language patterns, which suits drafting more than precise fact recall</strong> is correct because generating natural, well-structured text is a strength, while producing exact verified facts is not guaranteed by pattern prediction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is designed only for math and cannot write</b>: it is strong at writing, so this is false.</span><span class='qd'><b>It always fabricates every word it produces</b>: much of its output is accurate; it just is not guaranteed to be.</span><span class='qd'><b>It is limited to copying text verbatim from one source</b>: it generates new text rather than copying one source word-for-word.</span>" },
{ id:"D1-033", domain:1, obj:"1.2", diff:"medium", q:"Which of the following is a realistic limitation of generative AI that users should keep in mind?", options:["It can produce information that is outdated, biased, or simply incorrect","It can physically repair broken hardware","It never needs any human oversight","It always knows the user's private context"], answer:0, explain:"<strong>It can produce information that is outdated, biased, or simply incorrect</strong> is correct because these are genuine, well-documented limitations of generative AI output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It can physically repair broken hardware</b>: software AI cannot perform physical repairs.</span><span class='qd'><b>It never needs any human oversight</b>: human oversight is important precisely because output can be flawed.</span><span class='qd'><b>It always knows the user's private context</b>: it only knows what it was given and cannot access unshared personal context.</span>" },
{ id:"D1-034", domain:1, obj:"1.2", diff:"hard", q:"A user pastes a paragraph and asks the AI to summarize it. Why is this generally more reliable than asking the AI to recall an obscure historical date from memory?", options:["Because summarizing is impossible for AI","Because summarizing uses the provided text, while recalling a fact relies on uncertain training memory","Because the AI verifies historical dates with a librarian","Because obscure dates are always in the model's live feed"], answer:1, explain:"<strong>Because summarizing uses the provided text, while recalling a fact relies on uncertain training memory</strong> is correct because when the source text is supplied, the model works from it directly, whereas recalling an obscure fact depends on imperfect learned patterns.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because summarizing is impossible for AI</b>: summarizing is actually a common, reliable use.</span><span class='qd'><b>Because the AI verifies historical dates with a librarian</b>: the model does not consult a human librarian.</span><span class='qd'><b>Because obscure dates are always in the model's live feed</b>: base models do not have a live feed of facts.</span>" },
{ id:"D1-035", domain:1, obj:"1.2", diff:"medium", q:"Which statement correctly describes \"tokens\" in the context of how an LLM processes text?", options:["Tokens are physical coins the model uses","Tokens are passwords for logging in","Tokens are chunks of text, such as words or word pieces, that the model reads and predicts","Tokens are images the model draws"], answer:2, explain:"<strong>Tokens are chunks of text, such as words or word pieces, that the model reads and predicts</strong> is correct because LLMs break text into tokens and generate output by predicting the next token.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tokens are physical coins the model uses</b>: tokens here are units of text, not physical objects.</span><span class='qd'><b>Tokens are passwords for logging in</b>: this confuses the term with authentication tokens, which is a different meaning.</span><span class='qd'><b>Tokens are images the model draws</b>: tokens relate to text processing, not drawing images.</span>" },
{ id:"D1-036", domain:1, obj:"1.2", diff:"easy", q:"A generative AI tool says, \"I may make mistakes. Consider checking important information.\" Why do many tools show this kind of notice?", options:["To discourage anyone from ever using them","Because the tool is currently offline","Because the notice is legally banned","Because generative AI can produce incorrect output and users should verify important results"], answer:3, explain:"<strong>Because generative AI can produce incorrect output and users should verify important results</strong> is correct because such notices remind users of the real possibility of error and the value of checking important information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To discourage anyone from ever using them</b>: the notice encourages careful use, not avoidance.</span><span class='qd'><b>Because the tool is currently offline</b>: the notice is about accuracy, not availability.</span><span class='qd'><b>Because the notice is legally banned</b>: such notices are common and not banned.</span>" },
{ id:"D1-037", domain:1, obj:"1.2", diff:"hard", q:"Which scenario BEST illustrates that a generative AI does not \"understand\" the world the way people do?", options:["It confidently gives step-by-step directions to a city that does not exist","It correctly summarizes a clearly written memo","It rephrases a sentence you provided","It lists common synonyms for a word"], answer:0, explain:"<strong>It confidently gives step-by-step directions to a city that does not exist</strong> is correct because inventing detailed directions to a nonexistent place shows the model is generating plausible text without real-world understanding.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It correctly summarizes a clearly written memo</b>: accurate summarizing is a normal, reliable task and does not reveal a lack of understanding.</span><span class='qd'><b>It rephrases a sentence you provided</b>: rephrasing given text is a routine, dependable use.</span><span class='qd'><b>It lists common synonyms for a word</b>: providing synonyms is a straightforward language task, not a sign of failure.</span>" },
{ id:"D1-038", domain:1, obj:"1.2", diff:"medium", q:"Why is it risky to rely on a generative AI for medical, legal, or financial decisions without expert review?", options:["Because it cannot form sentences on those topics","Because its output may be inaccurate or incomplete and lacks professional accountability","Because it charges too much money","Because it refuses all such questions"], answer:1, explain:"<strong>Because its output may be inaccurate or incomplete and lacks professional accountability</strong> is correct because high-stakes decisions require verified, accountable expertise, and AI output can be wrong or missing important context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because it cannot form sentences on those topics</b>: it can readily produce text on these topics, which is part of the risk.</span><span class='qd'><b>Because it charges too much money</b>: cost is not the reason such reliance is risky.</span><span class='qd'><b>Because it refuses all such questions</b>: it will often answer, so the concern is accuracy, not refusal.</span>" },
{ id:"D1-039", domain:1, obj:"1.2", diff:"hard", q:"A colleague believes that because generative AI produced the same wrong answer twice, the answer must be correct. What is the flaw in that reasoning?", options:["Two identical answers always prove correctness","The model cannot repeat itself","Repetition of an answer does not verify its accuracy; the model can repeat the same mistake","Repeated answers come from a fact-checked source"], answer:2, explain:"<strong>Repetition of an answer does not verify its accuracy; the model can repeat the same mistake</strong> is correct because a model can consistently produce the same incorrect output, so repetition is not evidence of truth.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Two identical answers always prove correctness</b>: consistency is not the same as correctness.</span><span class='qd'><b>The model cannot repeat itself</b>: models can and do repeat answers.</span><span class='qd'><b>Repeated answers come from a fact-checked source</b>: repetition does not imply any fact-checking took place.</span>" },
{ id:"D1-040", domain:1, obj:"1.2", diff:"medium", q:"Which action BEST reduces the chance of being misled by a generative AI hallucination?", options:["Assuming detailed answers are automatically true","Ignoring the entire answer if any part seems detailed","Only asking questions the AI cannot answer","Cross-checking specific claims, names, and numbers against trusted sources"], answer:3, explain:"<strong>Cross-checking specific claims, names, and numbers against trusted sources</strong> is correct because verifying concrete details is the most effective safeguard against fabricated content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assuming detailed answers are automatically true</b>: detail can accompany hallucinations, so this increases risk.</span><span class='qd'><b>Ignoring the entire answer if any part seems detailed</b>: detail alone is not a reason to discard useful content.</span><span class='qd'><b>Only asking questions the AI cannot answer</b>: this does not address verifying the answers you do receive.</span>" },
{ id:"D1-041", domain:1, obj:"1.3", diff:"easy", q:"Which company created the ChatGPT assistant?", options:["OpenAI","Meta","Perplexity","Stability.ai"], answer:0, explain:"<strong>OpenAI</strong> is correct because ChatGPT is the conversational AI assistant developed by OpenAI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Meta</b>: Meta develops the Llama family of models, not ChatGPT.</span><span class='qd'><b>Perplexity</b>: Perplexity offers an answer engine for research, not ChatGPT.</span><span class='qd'><b>Stability.ai</b>: Stability.ai is known for image generation, not ChatGPT.</span>" },
{ id:"D1-042", domain:1, obj:"1.3", diff:"easy", q:"Which AI assistant is developed by Anthropic?", options:["Gemini","Claude","Grok","Copilot"], answer:1, explain:"<strong>Claude</strong> is correct because Claude is the AI assistant created by Anthropic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Gemini</b>: Gemini is Google's AI assistant, not Anthropic's.</span><span class='qd'><b>Grok</b>: Grok is developed by xAI, not Anthropic.</span><span class='qd'><b>Copilot</b>: Copilot is Microsoft's assistant, not Anthropic's.</span>" },
{ id:"D1-043", domain:1, obj:"1.3", diff:"easy", q:"Google's family of generative AI assistants is known as:", options:["Claude","Llama","Gemini","DALL-E"], answer:2, explain:"<strong>Gemini</strong> is correct because Gemini is Google's generative AI assistant.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Claude</b>: Claude is made by Anthropic, not Google.</span><span class='qd'><b>Llama</b>: Llama is Meta's open-source model family, not Google's assistant.</span><span class='qd'><b>DALL-E</b>: DALL-E is OpenAI's image generator, not Google's assistant.</span>" },
{ id:"D1-044", domain:1, obj:"1.3", diff:"easy", q:"Microsoft Copilot is BEST known for being integrated into which type of software?", options:["A video game console","A car navigation system","A kitchen appliance","Office productivity apps like Word and Excel"], answer:3, explain:"<strong>Office productivity apps like Word and Excel</strong> is correct because Microsoft Copilot is built into Microsoft 365 and Office apps to assist with documents, spreadsheets, and more.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A video game console</b>: Copilot is not a gaming console feature.</span><span class='qd'><b>A car navigation system</b>: Copilot is not a car navigation product.</span><span class='qd'><b>A kitchen appliance</b>: Copilot has nothing to do with kitchen appliances.</span>" },
{ id:"D1-045", domain:1, obj:"1.3", diff:"medium", q:"A researcher wants a tool that answers questions and cites its web sources like an \"answer engine.\" Which tool is designed for this?", options:["Perplexity","Midjourney","DALL-E","GitHub Copilot"], answer:0, explain:"<strong>Perplexity</strong> is correct because Perplexity is positioned as an answer engine that responds to questions and provides source citations for research.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Midjourney</b>: Midjourney generates images, not cited research answers.</span><span class='qd'><b>DALL-E</b>: DALL-E creates images from prompts, not sourced answers.</span><span class='qd'><b>GitHub Copilot</b>: GitHub Copilot assists with writing code, not research answers.</span>" },
{ id:"D1-046", domain:1, obj:"1.3", diff:"medium", q:"Which tool is specifically designed to help developers write and complete code inside their editor?", options:["Perplexity","GitHub Copilot","Midjourney","Stability.ai"], answer:1, explain:"<strong>GitHub Copilot</strong> is correct because GitHub Copilot suggests and completes code directly within a developer's editor.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Perplexity</b>: Perplexity is a research answer engine, not a code assistant.</span><span class='qd'><b>Midjourney</b>: Midjourney generates images, not code.</span><span class='qd'><b>Stability.ai</b>: Stability.ai focuses on image generation, not coding help.</span>" },
{ id:"D1-047", domain:1, obj:"1.3", diff:"medium", q:"Grok is a generative AI assistant developed by which organization?", options:["Google","Anthropic","xAI","Meta"], answer:2, explain:"<strong>xAI</strong> is correct because Grok is the AI assistant created by xAI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Google</b>: Google develops Gemini, not Grok.</span><span class='qd'><b>Anthropic</b>: Anthropic develops Claude, not Grok.</span><span class='qd'><b>Meta</b>: Meta develops Llama, not Grok.</span>" },
{ id:"D1-048", domain:1, obj:"1.3", diff:"medium", q:"Which of the following is Meta's family of open-source large language models?", options:["Claude","Gemini","Grok","Llama"], answer:3, explain:"<strong>Llama</strong> is correct because Llama is Meta's family of openly available large language models.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Claude</b>: Claude is Anthropic's assistant, not Meta's open model.</span><span class='qd'><b>Gemini</b>: Gemini is Google's assistant, not Meta's model.</span><span class='qd'><b>Grok</b>: Grok is xAI's assistant, not a Meta open-source model.</span>" },
{ id:"D1-049", domain:1, obj:"1.3", diff:"medium", q:"A designer wants to generate original images from text descriptions. Which set of tools is built for this purpose?", options:["DALL-E, Midjourney, and Stability.ai","ChatGPT, Claude, and Gemini","GitHub Copilot and Perplexity","Word, Excel, and PowerPoint"], answer:0, explain:"<strong>DALL-E, Midjourney, and Stability.ai</strong> is correct because all three are image-generation tools that create pictures from text prompts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ChatGPT, Claude, and Gemini</b>: these are primarily text assistants, though some may add image features, and the list is best known for conversation.</span><span class='qd'><b>GitHub Copilot and Perplexity</b>: these serve coding and research, not image generation.</span><span class='qd'><b>Word, Excel, and PowerPoint</b>: these are office apps, not image generators.</span>" },
{ id:"D1-050", domain:1, obj:"1.3", diff:"easy", q:"A student needs a tool that will answer a research question AND show links to the sources it used so the student can verify them. Which choice BEST fits?", options:["Midjourney, because it creates visuals","Perplexity, because it acts as an answer engine with citations","DALL-E, because it makes images from text","A standard word processor, because it stores documents"], answer:1, explain:"<strong>Perplexity, because it acts as an answer engine with citations</strong> is correct because Perplexity is designed to answer questions and present source links, which directly supports verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Midjourney, because it creates visuals</b>: Midjourney makes images and does not answer research questions with sources.</span><span class='qd'><b>DALL-E, because it makes images from text</b>: DALL-E generates images and provides no research citations.</span><span class='qd'><b>A standard word processor, because it stores documents</b>: a word processor only edits and stores text and does not answer questions with sources.</span>" },
{ id:"D1-051", domain:1, obj:"1.3", diff:"easy", q:"An organization wants an AI model they can download and run on their own infrastructure. Which option is MOST aligned with that goal?", options:["ChatGPT, accessed only through OpenAI's service","Perplexity, an online answer engine","Llama, an open-source model family","Midjourney, a hosted image service"], answer:2, explain:"<strong>Llama, an open-source model family</strong> is correct because open-source models like Llama can be downloaded and run on an organization's own systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ChatGPT, accessed only through OpenAI's service</b>: ChatGPT is used through OpenAI's hosted service rather than downloaded to run yourself.</span><span class='qd'><b>Perplexity, an online answer engine</b>: Perplexity is an online service, not a downloadable self-hosted model.</span><span class='qd'><b>Midjourney, a hosted image service</b>: Midjourney is a hosted image tool, not a self-hosted model.</span>" },
{ id:"D1-052", domain:1, obj:"1.3", diff:"medium", q:"Which pairing of tool and primary purpose is correct?", options:["GitHub Copilot — generating photorealistic paintings","DALL-E — completing lines of source code","Midjourney — summarizing legal contracts","Perplexity — research answers with cited sources"], answer:3, explain:"<strong>Perplexity — research answers with cited sources</strong> is correct because Perplexity's main purpose is answering questions with citations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GitHub Copilot — generating photorealistic paintings</b>: GitHub Copilot assists with code, not paintings.</span><span class='qd'><b>DALL-E — completing lines of source code</b>: DALL-E generates images, not code.</span><span class='qd'><b>Midjourney — summarizing legal contracts</b>: Midjourney creates images and does not summarize contracts.</span>" },
{ id:"D1-053", domain:1, obj:"1.3", diff:"hard", q:"A team already works heavily in Microsoft 365 and wants AI help drafting documents and analyzing spreadsheets inside those apps. Which tool is the MOST natural fit?", options:["Microsoft Copilot","Midjourney","Stability.ai","GitHub Copilot"], answer:0, explain:"<strong>Microsoft Copilot</strong> is correct because Microsoft Copilot is integrated into Microsoft 365 apps to help with documents and spreadsheets right where the team already works.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Midjourney</b>: Midjourney generates images and is not embedded in Office apps.</span><span class='qd'><b>Stability.ai</b>: Stability.ai focuses on image generation, not Office productivity.</span><span class='qd'><b>GitHub Copilot</b>: GitHub Copilot helps with code in developer editors, not Office document drafting.</span>" },
{ id:"D1-054", domain:1, obj:"1.3", diff:"easy", q:"DALL-E is a tool primarily used to:", options:["Balance a checkbook","Generate images from text prompts","Write software tests","Compress video files"], answer:1, explain:"<strong>Generate images from text prompts</strong> is correct because DALL-E is an image-generation model that creates pictures based on text descriptions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Balance a checkbook</b>: DALL-E does not perform accounting tasks.</span><span class='qd'><b>Write software tests</b>: DALL-E does not generate code or tests.</span><span class='qd'><b>Compress video files</b>: DALL-E does not compress files.</span>" },
{ id:"D1-055", domain:1, obj:"1.3", diff:"medium", q:"Which statement about Claude, ChatGPT, and Gemini is MOST accurate?", options:["They are all image-only generators","They are all made by the same company","They are all conversational AI assistants from different companies","They are all spreadsheet programs"], answer:2, explain:"<strong>They are all conversational AI assistants from different companies</strong> is correct because Claude (Anthropic), ChatGPT (OpenAI), and Gemini (Google) are competing conversational assistants.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are all image-only generators</b>: they are primarily text conversation assistants, not image-only tools.</span><span class='qd'><b>They are all made by the same company</b>: each comes from a different company.</span><span class='qd'><b>They are all spreadsheet programs</b>: none of them is a spreadsheet program.</span>" },
{ id:"D1-056", domain:1, obj:"1.3", diff:"hard", q:"An artist wants fine-grained community-driven control and the option of open image-generation models. Which provider is MOST associated with open image generation?", options:["GitHub Copilot","Perplexity","Microsoft Copilot","Stability.ai"], answer:3, explain:"<strong>Stability.ai</strong> is correct because Stability.ai is well known for openly available image-generation models.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GitHub Copilot</b>: GitHub Copilot is a coding assistant, not an image generator.</span><span class='qd'><b>Perplexity</b>: Perplexity is a research answer engine, not an image tool.</span><span class='qd'><b>Microsoft Copilot</b>: Microsoft Copilot focuses on productivity apps, not open image generation.</span>" },
{ id:"D1-057", domain:1, obj:"1.3", diff:"medium", q:"A user says, \"I want to brainstorm and draft written content through a back-and-forth chat.\" Which category of tool BEST fits?", options:["A conversational assistant such as ChatGPT or Claude","An image generator such as Midjourney","A code completion tool such as GitHub Copilot","A file compression utility"], answer:0, explain:"<strong>A conversational assistant such as ChatGPT or Claude</strong> is correct because conversational assistants are designed for interactive drafting and brainstorming through chat.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An image generator such as Midjourney</b>: image generators create pictures, not chat-based written drafts.</span><span class='qd'><b>A code completion tool such as GitHub Copilot</b>: code tools focus on programming, not general writing conversation.</span><span class='qd'><b>A file compression utility</b>: compression tools shrink files and do not chat or draft.</span>" },
{ id:"D1-058", domain:1, obj:"1.3", diff:"easy", q:"Which description correctly matches the tool to what makes it distinctive?", options:["Perplexity is distinctive for turning code into art","Grok is xAI's conversational assistant, distinct from Google's Gemini and Anthropic's Claude","Midjourney is distinctive for writing spreadsheets","GitHub Copilot is distinctive for citing research sources"], answer:1, explain:"<strong>Grok is xAI's conversational assistant, distinct from Google's Gemini and Anthropic's Claude</strong> is correct because Grok comes from xAI and is a separate assistant from those made by Google and Anthropic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Perplexity is distinctive for turning code into art</b>: Perplexity provides research answers, not code-to-art conversion.</span><span class='qd'><b>Midjourney is distinctive for writing spreadsheets</b>: Midjourney generates images, not spreadsheets.</span><span class='qd'><b>GitHub Copilot is distinctive for citing research sources</b>: GitHub Copilot assists with code, and citing research is Perplexity's strength.</span>" },
{ id:"D1-059", domain:1, obj:"1.3", diff:"medium", q:"Why might an organization choose an open-source model like Llama over a closed hosted service for certain projects?", options:["Because open-source models cannot be modified","Because it guarantees the model never makes mistakes","Because they can host and customize it themselves for more control","Because open-source means it needs no computing resources"], answer:2, explain:"<strong>Because they can host and customize it themselves for more control</strong> is correct because open-source models allow organizations to run and adapt the model on their own terms.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because open-source models cannot be modified</b>: open-source models are specifically meant to be modifiable.</span><span class='qd'><b>Because it guarantees the model never makes mistakes</b>: no model, open or closed, is error-free.</span><span class='qd'><b>Because open-source means it needs no computing resources</b>: running a model still requires computing resources.</span>" },
{ id:"D1-060", domain:1, obj:"1.3", diff:"hard", q:"A marketing team needs both written ad copy and matching promotional images. Which combination of tools is MOST appropriate?", options:["GitHub Copilot for the copy and Perplexity for the images","A spreadsheet app for both the copy and the images","A file backup service for both tasks","A conversational assistant for the copy and an image generator like DALL-E or Midjourney for the visuals"], answer:3, explain:"<strong>A conversational assistant for the copy and an image generator like DALL-E or Midjourney for the visuals</strong> is correct because pairing a text assistant with an image generator covers both the written and visual needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GitHub Copilot for the copy and Perplexity for the images</b>: GitHub Copilot targets code and Perplexity does research, so neither creates ad copy or images.</span><span class='qd'><b>A spreadsheet app for both the copy and the images</b>: a spreadsheet cannot generate marketing copy or images.</span><span class='qd'><b>A file backup service for both tasks</b>: backup software does not create content of any kind.</span>" },
{ id:"D1-061", domain:1, obj:"1.4", diff:"easy", q:"Which of these is a good everyday use of generative AI?", options:["Drafting a thank-you note you will personalize","Physically mailing the note for you","Guaranteeing the note is legally binding","Charging the recipient's phone"], answer:0, explain:"<strong>Drafting a thank-you note you will personalize</strong> is correct because drafting text that a person then edits is a classic, appropriate everyday use of generative AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physically mailing the note for you</b>: AI cannot physically mail anything.</span><span class='qd'><b>Guaranteeing the note is legally binding</b>: AI does not provide legal guarantees.</span><span class='qd'><b>Charging the recipient's phone</b>: charging a phone is unrelated to AI.</span>" },
{ id:"D1-062", domain:1, obj:"1.4", diff:"easy", q:"A student uses generative AI to brainstorm essay topics and then writes the essay themselves. This is BEST described as:", options:["Letting AI do all graded work dishonestly","Using AI as a helpful starting point","A task AI cannot assist with","Replacing the student's own thinking entirely"], answer:1, explain:"<strong>Using AI as a helpful starting point</strong> is correct because generating ideas to jump-start the student's own writing is a reasonable and constructive use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Letting AI do all graded work dishonestly</b>: the student still writes the essay, so this is not doing all the graded work.</span><span class='qd'><b>A task AI cannot assist with</b>: brainstorming is exactly something AI can assist with.</span><span class='qd'><b>Replacing the student's own thinking entirely</b>: the student performs the actual writing, so their thinking is not replaced.</span>" },
{ id:"D1-063", domain:1, obj:"1.4", diff:"easy", q:"Which everyday task is well suited to generative AI?", options:["Physically setting up chairs for a meeting","Replacing the office Wi-Fi router","Summarizing a long meeting transcript into key points","Signing a contract on someone's behalf"], answer:2, explain:"<strong>Summarizing a long meeting transcript into key points</strong> is correct because condensing text into key takeaways is a common and effective use of generative AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physically setting up chairs for a meeting</b>: physical setup is not something software AI can do.</span><span class='qd'><b>Replacing the office Wi-Fi router</b>: swapping hardware is unrelated to AI.</span><span class='qd'><b>Signing a contract on someone's behalf</b>: signing legal documents is not an appropriate AI task.</span>" },
{ id:"D1-064", domain:1, obj:"1.4", diff:"medium", q:"A user wants help rewriting a wordy paragraph to be clearer and shorter. Why is generative AI a good fit for this?", options:["Because it can legally certify the new paragraph","Because it prints the paragraph automatically","Because it can only lengthen text","Because it is strong at rephrasing and condensing text"], answer:3, explain:"<strong>Because it is strong at rephrasing and condensing text</strong> is correct because improving clarity and shortening writing is a core strength of generative AI language tools.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because it can legally certify the new paragraph</b>: AI does not provide legal certification.</span><span class='qd'><b>Because it prints the paragraph automatically</b>: printing is a hardware action AI does not perform.</span><span class='qd'><b>Because it can only lengthen text</b>: AI can shorten as well as lengthen text.</span>" },
{ id:"D1-065", domain:1, obj:"1.4", diff:"medium", q:"Which of the following is an appropriate creative use of generative AI?", options:["Generating concept art ideas for a personal project","Filing someone's taxes without review","Making binding legal rulings","Diagnosing a patient without a doctor"], answer:0, explain:"<strong>Generating concept art ideas for a personal project</strong> is correct because creating artistic ideas and visuals is a well-suited creative use of generative AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Filing someone's taxes without review</b>: high-stakes financial filing without review is inappropriate and risky.</span><span class='qd'><b>Making binding legal rulings</b>: AI cannot issue legal rulings.</span><span class='qd'><b>Diagnosing a patient without a doctor</b>: medical diagnosis requires a qualified professional, not unreviewed AI.</span>" },
{ id:"D1-066", domain:1, obj:"1.4", diff:"medium", q:"A team uses generative AI to draft internal FAQ answers, then a human reviews and approves them. Why is the human review step important?", options:["Because AI output is always wrong","To catch errors and ensure accuracy before publishing","To slow the process down for no reason","Because the AI demands approval"], answer:1, explain:"<strong>To catch errors and ensure accuracy before publishing</strong> is correct because human review verifies the AI-drafted content and corrects any mistakes before it is shared.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because AI output is always wrong</b>: AI output is often useful, so it is not always wrong; review manages the risk of errors.</span><span class='qd'><b>To slow the process down for no reason</b>: review adds value by improving quality, not delay for its own sake.</span><span class='qd'><b>Because the AI demands approval</b>: the AI does not require approval; the organization chooses to review for quality.</span>" },
{ id:"D1-067", domain:1, obj:"1.4", diff:"hard", q:"An employee wants to use generative AI to draft a customer email but the email will include specific account numbers and private details. What is the BEST practice?", options:["Paste all private details freely since AI keeps everything secret","Never use AI for any email","Draft with generic placeholders and avoid sharing sensitive data with the tool","Assume the tool cannot handle email at all"], answer:2, explain:"<strong>Draft with generic placeholders and avoid sharing sensitive data with the tool</strong> is correct because keeping private information out of the prompt protects confidentiality while still letting AI help with the wording.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paste all private details freely since AI keeps everything secret</b>: it is unsafe to assume a tool keeps shared data private, so sensitive details should be withheld.</span><span class='qd'><b>Never use AI for any email</b>: AI can still help with the general wording using placeholders, so a total ban is unnecessary.</span><span class='qd'><b>Assume the tool cannot handle email at all</b>: AI can assist with email drafting; the real concern is protecting sensitive data.</span>" },
{ id:"D1-068", domain:1, obj:"1.4", diff:"hard", q:"Which scenario shows the MOST effective everyday use of generative AI as a productivity aid?", options:["Copying its output directly into a report with no review","Using it to make final medical decisions alone","Trusting it to sign legal documents","Using it to generate a rough first draft that the user carefully edits and fact-checks"], answer:3, explain:"<strong>Using it to generate a rough first draft that the user carefully edits and fact-checks</strong> is correct because the strongest use combines AI speed for a draft with human editing and verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Copying its output directly into a report with no review</b>: skipping review risks publishing errors.</span><span class='qd'><b>Using it to make final medical decisions alone</b>: medical decisions need qualified professionals, not unaided AI.</span><span class='qd'><b>Trusting it to sign legal documents</b>: AI cannot appropriately sign legal documents.</span>" },
{ id:"D1-069", domain:1, obj:"1.4", diff:"medium", q:"Which use of generative AI is MOST appropriate for research support?", options:["Using it to suggest starting points and questions, then verifying facts independently","Treating every generated citation as automatically valid","Publishing its answers without any checking","Assuming it has read every document in the world"], answer:0, explain:"<strong>Using it to suggest starting points and questions, then verifying facts independently</strong> is correct because AI can help frame and jump-start research while the user confirms the actual facts from reliable sources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Treating every generated citation as automatically valid</b>: citations may be fabricated and must be verified.</span><span class='qd'><b>Publishing its answers without any checking</b>: publishing unchecked answers risks spreading errors.</span><span class='qd'><b>Assuming it has read every document in the world</b>: the model has limited training data, not every document ever written.</span>" },
{ id:"D1-070", domain:1, obj:"1.4", diff:"easy", q:"Generative AI can help with brainstorming because it can:", options:["Physically build a prototype","Quickly produce many varied ideas to consider","Guarantee every idea will succeed","Replace the need to make any decisions"], answer:1, explain:"<strong>Quickly produce many varied ideas to consider</strong> is correct because rapidly generating a range of ideas is a natural strength of generative AI for brainstorming.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physically build a prototype</b>: building physical prototypes is beyond software AI.</span><span class='qd'><b>Guarantee every idea will succeed</b>: AI cannot guarantee the success of ideas.</span><span class='qd'><b>Replace the need to make any decisions</b>: humans still choose among and refine the ideas.</span>" },
{ id:"D1-071", domain:1, obj:"1.4", diff:"medium", q:"A user wants generative AI to help translate the tone of a message from casual to professional. Why is this a suitable task?", options:["Because AI can legally approve the message","Because AI can send it through the postal service","Because adjusting wording and tone is a language task AI handles well","Because tone changes require special hardware"], answer:2, explain:"<strong>Because adjusting wording and tone is a language task AI handles well</strong> is correct because reworking phrasing and tone is squarely within a language model's capabilities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because AI can legally approve the message</b>: AI does not provide legal approval.</span><span class='qd'><b>Because AI can send it through the postal service</b>: AI cannot mail physical messages.</span><span class='qd'><b>Because tone changes require special hardware</b>: adjusting tone needs no special hardware.</span>" },
{ id:"D1-072", domain:1, obj:"1.4", diff:"hard", q:"An office worker relies entirely on generative AI to write a compliance report and submits it without reading it. What is the PRIMARY problem?", options:["The AI charged too much to write it","Compliance reports cannot be typed","The worker did not use enough tools","The report may contain errors or fabricated details the worker never caught"], answer:3, explain:"<strong>The report may contain errors or fabricated details the worker never caught</strong> is correct because submitting unreviewed AI output risks including inaccuracies, especially in a high-stakes compliance context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI charged too much to write it</b>: cost is not the core problem here.</span><span class='qd'><b>Compliance reports cannot be typed</b>: reports can certainly be typed; the issue is the lack of review.</span><span class='qd'><b>The worker did not use enough tools</b>: the problem is skipping review, not a shortage of tools.</span>" },
{ id:"D1-073", domain:1, obj:"1.4", diff:"medium", q:"Which of the following BEST demonstrates using generative AI responsibly for a work presentation?", options:["Generating a draft outline, then verifying data and tailoring it to the audience","Presenting AI output verbatim with no changes","Including made-up statistics because they sound impressive","Refusing to review any generated slides"], answer:0, explain:"<strong>Generating a draft outline, then verifying data and tailoring it to the audience</strong> is correct because responsible use pairs an AI-generated starting point with human verification and customization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Presenting AI output verbatim with no changes</b>: verbatim use skips needed review and tailoring.</span><span class='qd'><b>Including made-up statistics because they sound impressive</b>: using fabricated statistics is dishonest and risky.</span><span class='qd'><b>Refusing to review any generated slides</b>: skipping review invites uncorrected errors.</span>" },
{ id:"D1-074", domain:1, obj:"1.4", diff:"hard", q:"Why is generative AI often described as a \"co-pilot\" rather than an \"autopilot\" for knowledge work?", options:["Because it fully replaces the human with no oversight","Because it assists the human, who stays in control and reviews the results","Because it can only fly actual aircraft","Because it works without any human input at all"], answer:1, explain:"<strong>Because it assists the human, who stays in control and reviews the results</strong> is correct because the co-pilot idea emphasizes AI as a helper while the person remains responsible for the final output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because it fully replaces the human with no oversight</b>: that would be autopilot, which is not the intended model.</span><span class='qd'><b>Because it can only fly actual aircraft</b>: the term is a metaphor, not a literal aviation function.</span><span class='qd'><b>Because it works without any human input at all</b>: it depends on human prompts and review.</span>" },
{ id:"D1-075", domain:1, obj:"1.4", diff:"medium", q:"A writer uses generative AI to overcome writer's block by generating opening sentences. This is an example of using AI to:", options:["Publish the finished book automatically","Replace the writer's voice completely","Spark ideas and momentum that the writer then develops","Guarantee a bestseller"], answer:2, explain:"<strong>Spark ideas and momentum that the writer then develops</strong> is correct because using AI to get past a block and then continuing the work themselves is a practical, appropriate use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish the finished book automatically</b>: AI does not publish books on its own.</span><span class='qd'><b>Replace the writer's voice completely</b>: the writer develops the work, keeping their own voice.</span><span class='qd'><b>Guarantee a bestseller</b>: AI cannot guarantee commercial success.</span>" },
{ id:"D1-076", domain:1, obj:"1.4", diff:"hard", q:"A user asks generative AI to explain a difficult concept in simpler terms. What is the BEST way to benefit from the explanation?", options:["Accept it as fully authoritative without any checking","Assume it is wrong and discard it immediately","Ask it to keep making the explanation longer forever","Read the simplified explanation, then confirm key facts with a trusted source"], answer:3, explain:"<strong>Read the simplified explanation, then confirm key facts with a trusted source</strong> is correct because using AI to clarify a concept works best when you still verify the important details.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept it as fully authoritative without any checking</b>: unverified acceptance risks absorbing errors.</span><span class='qd'><b>Assume it is wrong and discard it immediately</b>: discarding a useful explanation outright is unnecessary.</span><span class='qd'><b>Ask it to keep making the explanation longer forever</b>: endless lengthening does not improve understanding or accuracy.</span>" },
{ id:"D1-077", domain:1, obj:"1.4", diff:"easy", q:"Which task is generative AI well suited to help with?", options:["Creating a first draft of a job description","Physically interviewing candidates in person","Deciding final salaries with no human input","Shaking hands with new hires"], answer:0, explain:"<strong>Creating a first draft of a job description</strong> is correct because drafting written content like a job description is a strong, appropriate use of generative AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physically interviewing candidates in person</b>: in-person interviewing is a human activity AI cannot perform.</span><span class='qd'><b>Deciding final salaries with no human input</b>: important decisions like salaries need human judgment.</span><span class='qd'><b>Shaking hands with new hires</b>: physical greetings are outside AI's abilities.</span>" },
{ id:"D1-078", domain:1, obj:"1.4", diff:"medium", q:"A person wants to use generative AI to study for an exam. Which approach is MOST effective and responsible?", options:["Trusting every generated fact as exam-ready truth","Generating practice questions and explanations, then verifying answers against course material","Using it to take the exam for them dishonestly","Assuming it cannot help with studying"], answer:1, explain:"<strong>Generating practice questions and explanations, then verifying answers against course material</strong> is correct because AI can create helpful study material as long as the learner checks it against trusted course content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trusting every generated fact as exam-ready truth</b>: generated facts can be wrong and must be verified.</span><span class='qd'><b>Using it to take the exam for them dishonestly</b>: cheating is unethical and defeats the purpose of studying.</span><span class='qd'><b>Assuming it cannot help with studying</b>: AI can meaningfully support studying when used well.</span>" },
{ id:"D1-079", domain:1, obj:"1.4", diff:"hard", q:"Which situation shows generative AI adding the MOST value while keeping risk low?", options:["Making the final call on a legal dispute","Prescribing medication to a patient","Drafting brainstorming ideas for a low-stakes internal newsletter","Approving a large financial transaction alone"], answer:2, explain:"<strong>Drafting brainstorming ideas for a low-stakes internal newsletter</strong> is correct because a low-stakes creative task is a strong fit where AI adds value with minimal risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Making the final call on a legal dispute</b>: legal decisions are high-stakes and require qualified humans.</span><span class='qd'><b>Prescribing medication to a patient</b>: prescribing requires a medical professional, not AI alone.</span><span class='qd'><b>Approving a large financial transaction alone</b>: approving major transactions unaided carries high risk.</span>" },
{ id:"D1-080", domain:1, obj:"1.4", diff:"medium", q:"A user wants generative AI to help draft social media captions in different styles. Why is this a good fit?", options:["Because AI can post them without any account","Because captions require specialized hardware","Because AI can guarantee viral success","Because producing varied written styles quickly is a strength of generative AI"], answer:3, explain:"<strong>Because producing varied written styles quickly is a strength of generative AI</strong> is correct because generating multiple stylistic options for text is well within a language model's abilities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because AI can post them without any account</b>: posting requires an account and human action.</span><span class='qd'><b>Because captions require specialized hardware</b>: writing captions needs no special hardware.</span><span class='qd'><b>Because AI can guarantee viral success</b>: AI cannot guarantee that content goes viral.</span>" },
{ id:"D1-081", domain:1, obj:"1.5", diff:"easy", q:"How does a generative AI chat tool differ from a traditional search engine?", options:["Generative AI composes an original answer, while a search engine returns a list of existing web links","A search engine composes original paragraphs while AI only returns links","They are exactly the same thing","A search engine cannot handle any queries"], answer:0, explain:"<strong>Generative AI composes an original answer, while a search engine returns a list of existing web links</strong> is correct because generative AI writes a response, whereas a search engine points you to existing pages.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A search engine composes original paragraphs while AI only returns links</b>: this reverses their roles.</span><span class='qd'><b>They are exactly the same thing</b>: they work differently, so they are not the same.</span><span class='qd'><b>A search engine cannot handle any queries</b>: search engines are built to handle queries.</span>" },
{ id:"D1-082", domain:1, obj:"1.5", diff:"easy", q:"Which statement BEST contrasts generative AI with traditional software?", options:["Generative AI always follows exactly one fixed rule","Traditional software follows fixed programmed rules, while generative AI produces varied output from learned patterns","Traditional software can never be predictable","Generative AI cannot produce any output"], answer:1, explain:"<strong>Traditional software follows fixed programmed rules, while generative AI produces varied output from learned patterns</strong> is correct because conventional programs behave deterministically by design, whereas generative AI can generate different, pattern-based results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generative AI always follows exactly one fixed rule</b>: generative AI does not follow a single fixed rule; it predicts from patterns.</span><span class='qd'><b>Traditional software can never be predictable</b>: traditional software is generally predictable, not the opposite.</span><span class='qd'><b>Generative AI cannot produce any output</b>: generative AI is defined by producing output.</span>" },
{ id:"D1-083", domain:1, obj:"1.5", diff:"medium", q:"A user asks, \"Write me a short poem about the ocean.\" Why is a generative AI assistant a better fit than a search engine for this request?", options:["A search engine would create a brand-new poem instantly","A search engine always writes better poems","A generative AI can compose an original poem, while a search engine mainly finds existing pages","Generative AI can only find links, not write"], answer:2, explain:"<strong>A generative AI can compose an original poem, while a search engine mainly finds existing pages</strong> is correct because writing a new poem is a generation task, which is what generative AI does and a search engine does not.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A search engine would create a brand-new poem instantly</b>: a search engine finds existing content rather than composing new poems.</span><span class='qd'><b>A search engine always writes better poems</b>: search engines do not write poems at all.</span><span class='qd'><b>Generative AI can only find links, not write</b>: generative AI writes content and does not merely return links.</span>" },
{ id:"D1-084", domain:1, obj:"1.5", diff:"medium", q:"When would a traditional search engine be a BETTER choice than a generative AI chatbot?", options:["When you want an original story written for you","When you want text summarized into your own words","When you want brainstormed ideas","When you need to find the official website or current page for a specific organization"], answer:3, explain:"<strong>When you need to find the official website or current page for a specific organization</strong> is correct because search engines excel at locating specific, current, authoritative web pages.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>When you want an original story written for you</b>: writing a story is a generation task better suited to generative AI.</span><span class='qd'><b>When you want text summarized into your own words</b>: summarizing is a generative AI strength.</span><span class='qd'><b>When you want brainstormed ideas</b>: brainstorming is well suited to generative AI.</span>" },
{ id:"D1-085", domain:1, obj:"1.5", diff:"medium", q:"Which statement about traditional software behavior is TRUE compared to generative AI?", options:["Given the same input, traditional software typically produces the same output every time","Traditional software always gives a different answer each run","Traditional software learns new behavior from every user","Traditional software cannot be tested"], answer:0, explain:"<strong>Given the same input, traditional software typically produces the same output every time</strong> is correct because conventional programs are deterministic, unlike generative AI, which can vary its responses.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Traditional software always gives a different answer each run</b>: that describes variable, not traditional deterministic, behavior.</span><span class='qd'><b>Traditional software learns new behavior from every user</b>: traditional software does not learn from users the way ML systems can.</span><span class='qd'><b>Traditional software cannot be tested</b>: traditional software is routinely tested.</span>" },
{ id:"D1-086", domain:1, obj:"1.5", diff:"hard", q:"A team debates whether to use a generative AI tool or a rules-based program to calculate exact payroll amounts. Which is the BETTER choice and why?", options:["Generative AI, because approximate answers are fine for payroll","A rules-based program, because exact, repeatable calculations require deterministic logic","Generative AI, because it never makes arithmetic mistakes","Either one, since both guarantee identical exact results"], answer:1, explain:"<strong>A rules-based program, because exact, repeatable calculations require deterministic logic</strong> is correct because payroll demands precise, consistent results that deterministic software reliably provides.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generative AI, because approximate answers are fine for payroll</b>: payroll requires exact figures, not approximations.</span><span class='qd'><b>Generative AI, because it never makes arithmetic mistakes</b>: generative AI can make arithmetic errors.</span><span class='qd'><b>Either one, since both guarantee identical exact results</b>: generative AI does not guarantee identical exact results the way deterministic code does.</span>" },
{ id:"D1-087", domain:1, obj:"1.5", diff:"hard", q:"Why might a research answer engine like Perplexity be positioned between a chatbot and a search engine?", options:["It only returns raw links with no answer","It refuses to search the web at all","It generates a written answer while also citing web sources it drew from","It is identical to a plain search engine with no answer"], answer:2, explain:"<strong>It generates a written answer while also citing web sources it drew from</strong> is correct because an answer engine combines composed answers, like a chatbot, with source citations, like search results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It only returns raw links with no answer</b>: it provides a composed answer, not just links.</span><span class='qd'><b>It refuses to search the web at all</b>: answer engines draw on web sources to respond.</span><span class='qd'><b>It is identical to a plain search engine with no answer</b>: it differs from a plain search engine by generating an answer.</span>" },
{ id:"D1-088", domain:1, obj:"1.5", diff:"medium", q:"Which task is a clear reason to choose generative AI over traditional software?", options:["Performing an exact, audited financial ledger calculation","Enforcing a strict access-control rule every time","Sorting a fixed list in exactly the same order each run","Producing a customized, human-sounding draft from a short prompt"], answer:3, explain:"<strong>Producing a customized, human-sounding draft from a short prompt</strong> is correct because flexible, natural-language generation is exactly where generative AI outshines rigid traditional software.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Performing an exact, audited financial ledger calculation</b>: exact audited math is better handled by deterministic software.</span><span class='qd'><b>Enforcing a strict access-control rule every time</b>: strict rule enforcement suits deterministic logic.</span><span class='qd'><b>Sorting a fixed list in exactly the same order each run</b>: consistent sorting is a job for traditional software.</span>" },
{ id:"D1-089", domain:1, obj:"1.5", diff:"medium", q:"An organization needs a tool that always returns the identical, verifiable result for the same input for regulatory reasons. Why is generative AI a POOR fit?", options:["Because generative AI output can vary and is not guaranteed to be reproducible","Because generative AI cannot produce any text","Because generative AI is only for images","Because generative AI is faster than any rule"], answer:0, explain:"<strong>Because generative AI output can vary and is not guaranteed to be reproducible</strong> is correct because regulatory needs for identical, verifiable results conflict with generative AI's variable, probabilistic output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because generative AI cannot produce any text</b>: generative AI does produce text; the issue is reproducibility.</span><span class='qd'><b>Because generative AI is only for images</b>: generative AI handles text and more, so this is false.</span><span class='qd'><b>Because generative AI is faster than any rule</b>: speed is not the reason it is a poor fit here.</span>" },
{ id:"D1-090", domain:1, obj:"1.5", diff:"medium", q:"Which of the following BEST explains when AI is NOT the right tool for a job?", options:["When the task involves drafting text","When the task needs exact, guaranteed, reproducible results better handled by deterministic software","When the task involves brainstorming","When the task involves summarizing a document"], answer:1, explain:"<strong>When the task needs exact, guaranteed, reproducible results better handled by deterministic software</strong> is correct because tasks requiring precise, repeatable outcomes are better suited to traditional programmed logic than to generative AI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>When the task involves drafting text</b>: drafting is a good use of generative AI.</span><span class='qd'><b>When the task involves brainstorming</b>: brainstorming fits generative AI well.</span><span class='qd'><b>When the task involves summarizing a document</b>: summarizing is a strong use of generative AI.</span>" },
{ id:"D1-091", domain:1, obj:"1.5", diff:"easy", q:"A user needs the current, official train schedule for today. Which tool is generally the BETTER first choice?", options:["A generative AI with an unknown training cutoff","An image generator","A search engine or the official transit site","A code completion tool"], answer:2, explain:"<strong>A search engine or the official transit site</strong> is correct because current, authoritative schedule information is best found through a search engine or the official source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A generative AI with an unknown training cutoff</b>: a base model may lack up-to-date schedule data.</span><span class='qd'><b>An image generator</b>: an image generator does not provide schedule information.</span><span class='qd'><b>A code completion tool</b>: a code tool is unrelated to finding a train schedule.</span>" },
{ id:"D1-092", domain:1, obj:"1.5", diff:"medium", q:"Why is deciding \"when to use AI\" an important AI-literacy skill?", options:["Because AI should be used for absolutely every task","Because AI should never be used for any task","Because the choice of tool never matters","Because matching the tool to the task leads to better, safer, and more efficient results"], answer:3, explain:"<strong>Because matching the tool to the task leads to better, safer, and more efficient results</strong> is correct because knowing when AI fits, and when it does not, produces stronger outcomes and avoids misuse.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because AI should be used for absolutely every task</b>: some tasks are better handled without AI.</span><span class='qd'><b>Because AI should never be used for any task</b>: AI is genuinely useful for many tasks.</span><span class='qd'><b>Because the choice of tool never matters</b>: choosing the right tool clearly affects results.</span>" },
{ id:"D1-093", domain:1, obj:"1.5", diff:"easy", q:"A user wants both a synthesized answer and the ability to check original sources for a research question. Which best describes the ideal tool behavior?", options:["It writes a clear answer and links the sources so the user can verify them","It hides its sources entirely","It only lists links with no synthesis","It refuses to answer research questions"], answer:0, explain:"<strong>It writes a clear answer and links the sources so the user can verify them</strong> is correct because an answer engine that both synthesizes and cites sources supports understanding and verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It hides its sources entirely</b>: hiding sources prevents the verification the user wants.</span><span class='qd'><b>It only lists links with no synthesis</b>: links alone do not provide the synthesized answer requested.</span><span class='qd'><b>It refuses to answer research questions</b>: refusing to answer defeats the purpose.</span>" },
{ id:"D1-094", domain:1, obj:"1.5", diff:"medium", q:"Which comparison correctly distinguishes a chatbot answer from a search engine result?", options:["A chatbot only returns links, while a search engine writes essays","A chatbot generates a written response, while a search result is a link to an existing page","Both always cite the same sources automatically","Neither can respond to a question"], answer:1, explain:"<strong>A chatbot generates a written response, while a search result is a link to an existing page</strong> is correct because a chatbot composes an answer, whereas a search result directs you to a preexisting page.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A chatbot only returns links, while a search engine writes essays</b>: this reverses their behaviors.</span><span class='qd'><b>Both always cite the same sources automatically</b>: they do not automatically cite identical sources.</span><span class='qd'><b>Neither can respond to a question</b>: both respond to questions in their own ways.</span>" },
{ id:"D1-095", domain:1, obj:"1.5", diff:"hard", q:"A developer must decide between a generative AI code assistant and a strict validation script that must reject invalid input identically every time. Which is the BETTER fit for the strict validation, and why?", options:["The AI assistant, because it varies its decisions creatively","The AI assistant, because strict rules are unnecessary","The validation script, because deterministic rules guarantee consistent enforcement","Either one, since both behave identically on every input"], answer:2, explain:"<strong>The validation script, because deterministic rules guarantee consistent enforcement</strong> is correct because strict, identical validation demands predictable rule-based logic rather than variable AI output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI assistant, because it varies its decisions creatively</b>: variability is undesirable for strict validation.</span><span class='qd'><b>The AI assistant, because strict rules are unnecessary</b>: strict rules are exactly what this task requires.</span><span class='qd'><b>Either one, since both behave identically on every input</b>: generative AI does not behave identically every time like a deterministic script.</span>" },
{ id:"D1-096", domain:1, obj:"1.5", diff:"easy", q:"Which is a strength of generative AI compared to a plain search engine?", options:["It can only show a ranked list of links","It cannot process a written prompt","It refuses to generate text","It can draft a customized response in natural language"], answer:3, explain:"<strong>It can draft a customized response in natural language</strong> is correct because generating tailored, natural-language content is something generative AI does that a plain search engine does not.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It can only show a ranked list of links</b>: showing ranked links describes a search engine, not generative AI.</span><span class='qd'><b>It cannot process a written prompt</b>: generative AI is built to process written prompts.</span><span class='qd'><b>It refuses to generate text</b>: generating text is its core function.</span>" },
{ id:"D1-097", domain:1, obj:"1.5", diff:"medium", q:"A user asks a generative AI to \"find the exact page number of a quote in a specific printed book.\" Why might this be a poor use?", options:["The model may not have exact page-level details and could invent one","Generative AI cannot read any text","Search engines cannot handle books","Page numbers require an image generator"], answer:0, explain:"<strong>The model may not have exact page-level details and could invent one</strong> is correct because precise, verifiable references like exact page numbers are not guaranteed and may be fabricated by the model.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generative AI cannot read any text</b>: generative AI can process text; the issue is exact verifiable detail.</span><span class='qd'><b>Search engines cannot handle books</b>: search engines can help locate book information.</span><span class='qd'><b>Page numbers require an image generator</b>: image generators are irrelevant to finding a page number.</span>" },
{ id:"D1-098", domain:1, obj:"1.5", diff:"hard", q:"Which scenario BEST demonstrates matching the right tool to the task?", options:["Using an image generator to calculate exact taxes","Using a search engine for the latest official news and a chatbot to draft a summary of it","Using a code assistant to find today's weather forecast","Using a chatbot as the sole source for a legally binding contract"], answer:1, explain:"<strong>Using a search engine for the latest official news and a chatbot to draft a summary of it</strong> is correct because it pairs a search engine's current-information strength with a chatbot's drafting strength.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Using an image generator to calculate exact taxes</b>: image generators cannot perform tax calculations.</span><span class='qd'><b>Using a code assistant to find today's weather forecast</b>: a code assistant is not a weather source.</span><span class='qd'><b>Using a chatbot as the sole source for a legally binding contract</b>: a legally binding contract should not rely solely on an unreviewed chatbot.</span>" },
{ id:"D1-099", domain:1, obj:"1.5", diff:"medium", q:"Why can it be helpful to use a search engine and a generative AI tool together?", options:["They cancel each other out and give no results","Using both is always forbidden","The search engine finds current, verifiable sources while the AI helps organize or summarize them","The AI blocks the search engine from working"], answer:2, explain:"<strong>The search engine finds current, verifiable sources while the AI helps organize or summarize them</strong> is correct because combining current source-finding with AI summarization leverages the strengths of each.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They cancel each other out and give no results</b>: they complement rather than cancel each other.</span><span class='qd'><b>Using both is always forbidden</b>: using both together is a common, allowed practice.</span><span class='qd'><b>The AI blocks the search engine from working</b>: an AI tool does not block a search engine.</span>" },
{ id:"D1-100", domain:1, obj:"1.5", diff:"hard", q:"A knowledge worker concludes: \"I should pick between generative AI, a search engine, or traditional software based on what the task requires.\" Why is this the RIGHT mindset?", options:["Because generative AI is always the correct answer","Because search engines are obsolete","Because traditional software can do everything AI can, identically","Because each tool has different strengths, and the best results come from matching the tool to the need"], answer:3, explain:"<strong>Because each tool has different strengths, and the best results come from matching the tool to the need</strong> is correct because thoughtful selection among AI, search, and traditional software produces the most effective and appropriate outcomes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because generative AI is always the correct answer</b>: generative AI is not always the best fit for every task.</span><span class='qd'><b>Because search engines are obsolete</b>: search engines remain useful for current, verifiable information.</span><span class='qd'><b>Because traditional software can do everything AI can, identically</b>: traditional software cannot replicate generative AI's flexible content creation.</span>" }
);
